var SUPABASE_URL = "https://kzzqloklnxlqbccxbxgr.supabase.co";
var SUPABASE_ANON_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt6enFsb2tsbnhscWJjY3hieGdyIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzI0NzA4MDMsImV4cCI6MjA4ODA0NjgwM30.lCqD2KymgqQf3h8xUHIht7PeBcmvPVSXxvqsL45Mrko";
async function supabaseFetch(table, query = "", options = {}) {
  const url = `${SUPABASE_URL}/rest/v1/${table}${query ? "?" + query : ""}`;
  try {
    const res = await fetch(url, {
      headers: {
        "apikey": SUPABASE_ANON_KEY,
        "Authorization": `Bearer ${SUPABASE_ANON_KEY}`,
        "Accept": "application/json"
      },
      signal: options.signal
    });
    if (!res.ok) {
      return { data: null, error: `HTTP ${res.status}: ${res.statusText}`, status: res.status };
    }
    const data = await res.json();
    return { data, error: null, status: res.status };
  } catch (e) {
    return { data: null, error: e.message, status: 0 };
  }
}

// src/services/cache-db.ts
var DB_NAME = "medkitt-cache";
var DB_VERSION = 4;
var DATA_VERSION = 1;
var DATA_VERSION_KEY = "medkitt-data-version";
var dbPromise = null;
async function checkDataVersion(db) {
  const stored = localStorage.getItem(DATA_VERSION_KEY);
  if (stored === String(DATA_VERSION)) return;
  const storeNames = ["drugs", "categories", "category_trees", "decision_nodes", "tree_citations", "sync_meta", "info_pages"];
  const tx = db.transaction(storeNames, "readwrite");
  for (const name of storeNames) {
    tx.objectStore(name).clear();
  }
  await new Promise((resolve, reject) => {
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
  localStorage.setItem(DATA_VERSION_KEY, String(DATA_VERSION));
}
function openDB() {
  if (dbPromise) return dbPromise;
  dbPromise = new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);
    request.onerror = () => reject(request.error);
    request.onsuccess = async () => {
      await checkDataVersion(request.result);
      resolve(request.result);
    };
    request.onupgradeneeded = (event) => {
      const db = event.target.result;
      if (!db.objectStoreNames.contains("drugs")) {
        db.createObjectStore("drugs", { keyPath: "id" });
      }
      if (!db.objectStoreNames.contains("categories")) {
        db.createObjectStore("categories", { keyPath: "id" });
      }
      if (!db.objectStoreNames.contains("category_trees")) {
        db.createObjectStore("category_trees", { keyPath: ["category_id", "tree_id"] });
      }
      if (!db.objectStoreNames.contains("decision_nodes")) {
        db.createObjectStore("decision_nodes", { keyPath: ["id", "tree_id"] });
      }
      if (!db.objectStoreNames.contains("tree_citations")) {
        db.createObjectStore("tree_citations", { keyPath: ["tree_id", "num"] });
      }
      if (!db.objectStoreNames.contains("sync_meta")) {
        db.createObjectStore("sync_meta", { keyPath: "key" });
      }
      if (!db.objectStoreNames.contains("info_pages")) {
        db.createObjectStore("info_pages", { keyPath: "id" });
      }
    };
  });
  return dbPromise;
}
async function cacheGetAll(storeName) {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(storeName, "readonly");
    const request = tx.objectStore(storeName).getAll();
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}
async function cachePutAll(storeName, records) {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(storeName, "readwrite");
    const store = tx.objectStore(storeName);
    store.clear();
    for (const record of records) {
      store.put(record);
    }
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
}
async function cacheGetFiltered(storeName, filter) {
  const all = await cacheGetAll(storeName);
  return all.filter(filter);
}
async function cachePutMany(storeName, records) {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction(storeName, "readwrite");
    const store = tx.objectStore(storeName);
    for (const record of records) {
      store.put(record);
    }
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
}
async function setLastSync(dataType) {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction("sync_meta", "readwrite");
    tx.objectStore("sync_meta").put({ key: dataType, timestamp: Date.now() });
    tx.oncomplete = () => resolve();
    tx.onerror = () => reject(tx.error);
  });
}
async function getLastSync(dataType) {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const tx = db.transaction("sync_meta", "readonly");
    const request = tx.objectStore("sync_meta").get(dataType);
    request.onsuccess = () => resolve(request.result?.timestamp ?? null);
    request.onerror = () => reject(request.error);
  });
}

// src/services/category-service.ts
init_categories();
var categoryCache = [];
var colorsCache = {};
var initialized = false;
var STALE_MS = 60 * 60 * 1e3;
function buildCategories(catRows, treeRows) {
  const treesByCategory = /* @__PURE__ */ new Map();
  for (const row of treeRows) {
    const tree = row.decision_trees;
    const meta = {
      id: tree.id,
      title: row.display_title ?? tree.title,
      subtitle: row.display_subtitle ?? tree.subtitle,
      categoryId: row.category_id,
      version: tree.version,
      nodeCount: tree.node_count,
      entryNodeId: row.entry_node_id ?? tree.entry_node_id
    };
    const list = treesByCategory.get(row.category_id) ?? [];
    list.push(meta);
    treesByCategory.set(row.category_id, list);
  }
  return catRows.map((row) => ({
    id: row.id,
    name: row.name,
    icon: row.icon,
    decisionTrees: treesByCategory.get(row.id) ?? [],
    isCustom: row.is_custom
  }));
}
function buildColors(catRows) {
  const colors = {};
  for (const row of catRows) {
    if (row.card_color && row.icon_bg) {
      colors[row.id] = {
        card: row.card_color,
        iconBg: row.icon_bg,
        ...row.text_color ? { textColor: row.text_color } : {},
        ...row.outline ? { outline: row.outline } : {}
      };
    }
  }
  return colors;
}
function setCategoryCache(categories, colors) {
  categoryCache = categories;
  colorsCache = colors;
}
async function refreshFromSupabase() {
  const [catResult, treeResult] = await Promise.all([
    supabaseFetch("categories", "select=*&order=sort_order"),
    supabaseFetch("category_trees", "select=*,decision_trees(*)&order=sort_order")
  ]);
  if (catResult.data && catResult.data.length > 0 && treeResult.data) {
    const categories = buildCategories(catResult.data, treeResult.data);
    const colors = buildColors(catResult.data);
    setCategoryCache(categories, colors);
    await mergeHardcodedConsults();
    await cachePutAll("categories", catResult.data);
    await cachePutAll("category_trees", treeResult.data);
    await setLastSync("categories");
  }
}
async function loadHardcodedFallback() {
  const mod = await Promise.resolve().then(() => (init_categories(), categories_exports));
  setCategoryCache(mod.getAllCategories(), mod.CATEGORY_COLORS);
}
async function mergeHardcodedConsults() {
  const mod = await Promise.resolve().then(() => (init_categories(), categories_exports));
  const hardcoded = mod.getAllCategories();
  for (const hCat of hardcoded) {
    const cached = categoryCache.find((c) => c.id === hCat.id);
    if (!cached) continue;
    const cachedIds = new Set(cached.decisionTrees.map((t) => t.id));
    const missing = hCat.decisionTrees.filter((t) => !cachedIds.has(t.id));
    if (missing.length > 0) {
      cached.decisionTrees.push(...missing);
    }
  }
}
async function initCategories() {
  if (initialized) return;
  try {
    const cachedCats = await cacheGetAll("categories");
    const cachedTrees = await cacheGetAll("category_trees");
    if (cachedCats.length > 0) {
      const categories = buildCategories(cachedCats, cachedTrees);
      const colors = buildColors(cachedCats);
      setCategoryCache(categories, colors);
      initialized = true;
    }
  } catch {
  }
  if (!initialized) {
    await loadHardcodedFallback();
    initialized = true;
  } else {
    await mergeHardcodedConsults();
  }
  try {
    const lastSync = await getLastSync("categories");
    const isStale = !lastSync || Date.now() - lastSync > STALE_MS;
    if (isStale) {
      refreshFromSupabase().catch(() => {
      });
    }
  } catch {
  }
}
function getAllCategories2() {
  try {
    const raw = localStorage.getItem("em-custom-categories");
    if (raw) {
      const custom = JSON.parse(raw);
      return [...categoryCache, ...custom];
    }
  } catch {
  }
  return categoryCache;
}
function getCategoryColors() {
  return colorsCache;
}

